const updateNode = `-- name: UpdateNode :one
UPDATE nodes
SET name = $2, type = $3, health = $4, purpose = $5, current_status = $6, this_week_focus = $7, decision_queue = $8, delegation_ready = $9, context_id = $10, updated_at = NOW()
WHERE id = $1
RETURNING id, user_id, parent_id, context_id, name, type, health, purpose, current_status, this_week_focus, decision_queue, delegation_ready, is_active, is_archived, sort_order, created_at, updated_at
`

type UpdateNodeParams struct {
	ID              pgtype.UUID    `json:"id"`
	Name            string         `json:"name"`
	Type            Nodetype       `json:"type"`
	Health          NullNodehealth `json:"health"`
	Purpose         *string        `json:"purpose"`
	CurrentStatus   *string        `json:"current_status"`
	ThisWeekFocus   []byte         `json:"this_week_focus"`
	DecisionQueue   []byte         `json:"decision_queue"`
	DelegationReady []byte         `json:"delegation_ready"`
	ContextID       pgtype.UUID    `json:"context_id"`
}

func (q *Queries) UpdateNode(ctx context.Context, arg UpdateNodeParams) (Node, error) {
	row := q.db.QueryRow(ctx, updateNode,
		arg.ID,
		arg.Name,
		arg.Type,
		arg.Health,
		arg.Purpose,
		arg.CurrentStatus,
		arg.ThisWeekFocus,
		arg.DecisionQueue,
		arg.DelegationReady,
		arg.ContextID,
	)
	var i Node
	err := row.Scan(
		&i.ID,
		&i.UserID,
		&i.ParentID,
		&i.ContextID,
		&i.Name,
		&i.Type,
		&i.Health,
		&i.Purpose,
		&i.CurrentStatus,
		&i.ThisWeekFocus,
		&i.DecisionQueue,
		&i.DelegationReady,
		&i.IsActive,
		&i.IsArchived,
		&i.SortOrder,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

